import { useEffect, useMemo, useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { supabase } from '../lib/supabase';
import { useAuth } from '../context/AuthContext';
import { ensureTournamentTableConnection, getCachedTournamentTable } from '../lib/tournamentConnections';
import styles from './TournamentLobby.module.css';

interface TournamentRow {
  id: number;
  tournament_name: string;
  start_date: string;
  max_players: number;
  min_players: number;
  players: string[];
  ranked: boolean;
  time_per_level: number;
}

interface ProfileRow {
  user_id: string;
  username: string;
  elo: number;
}

function formatDate(value: string) {
  return new Intl.DateTimeFormat('fr-FR', {
    day: '2-digit',
    month: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
  }).format(new Date(value));
}

function statusLabel(tournament: TournamentRow | null) {
  if (!tournament) return 'Chargement';
  if (tournament.players.length >= tournament.max_players) return 'Complet';
  if (new Date(tournament.start_date).getTime() <= Date.now()) return 'En cours';
  return 'En attente';
}

export default function TournamentLobby() {
  const navigate = useNavigate();
  const { tournamentId } = useParams();
  const { user } = useAuth();
  const numericTournamentId = Number(tournamentId);

  const [tournament, setTournament] = useState<TournamentRow | null>(null);
  const [profiles, setProfiles] = useState<ProfileRow[]>([]);
  const [tableId, setTableId] = useState<number | null>(null);
  const [feedback, setFeedback] = useState('');

  const joined = Boolean(user && tournament?.players.includes(user.id));
  const seats = useMemo(() => {
    const players = tournament?.players ?? [];
    return Array.from({ length: tournament?.max_players ?? 10 }, (_, index) => players[index] ?? null);
  }, [tournament]);

  useEffect(() => {
    if (!Number.isFinite(numericTournamentId)) {
      navigate('/tournaments');
      return;
    }

    let cancelled = false;

    const fetchTournament = async () => {
      const { data, error } = await supabase.functions.invoke('list-tournaments');
      if (cancelled) return;

      const next = ((data?.tournaments ?? []) as TournamentRow[]).find(item => item.id === numericTournamentId) ?? null;
      if (error || data?.error || !next) {
        setFeedback('Tournoi introuvable.');
        setTournament(null);
        return;
      }

      setTournament(next);
      setFeedback('');

      if (next.players.length > 0) {
        const { data: profileRows } = await supabase
          .from('profiles')
          .select('user_id, username, elo')
          .in('user_id', next.players);

        if (!cancelled) {
          setProfiles((profileRows ?? []) as ProfileRow[]);
        }
      } else {
        setProfiles([]);
      }
    };

    fetchTournament();
    const interval = window.setInterval(fetchTournament, 5000);

    return () => {
      cancelled = true;
      window.clearInterval(interval);
    };
  }, [navigate, numericTournamentId]);

  useEffect(() => {
    if (!user || !joined || !tournament) return;

    const setup = async () => {
      const cached = getCachedTournamentTable(tournament.id, user.id);
      if (cached) {
        setTableId(cached);
        return;
      }

      const { data: { session } } = await supabase.auth.getSession();
      if (!session?.access_token) return;

      const assigned = await ensureTournamentTableConnection({
        tournamentId: tournament.id,
        userId: user.id,
        accessToken: session.access_token,
        onAssigned: setTableId,
      });
      if (assigned) setTableId(assigned);
    };

    setup();
  }, [joined, tournament, user]);

  const openTable = async () => {
    if (!user || !tournament) {
      navigate('/login');
      return;
    }

    const cached = tableId ?? getCachedTournamentTable(tournament.id, user.id);
    if (cached) {
      navigate(`/game/${cached}`, { state: { tournamentId: tournament.id } });
      return;
    }

    setFeedback('Connexion à ta table...');
    const { data: { session } } = await supabase.auth.getSession();
    if (!session?.access_token) {
      navigate('/login');
      return;
    }

    const assigned = await ensureTournamentTableConnection({
      tournamentId: tournament.id,
      userId: user.id,
      accessToken: session.access_token,
      onAssigned: setTableId,
    });

    if (assigned) {
      navigate(`/game/${assigned}`, { state: { tournamentId: tournament.id } });
    } else {
      setFeedback('Table encore indisponible.');
    }
  };

  return (
    <div className={styles.page}>
      <button className={styles.backButton} onClick={() => navigate('/tournaments')} aria-label="Retour aux tournois">
        <span />
      </button>

      <main className={styles.shell}>
        <section className={styles.hero}>
          <div>
            <span className={styles.eyebrow}>Lobby tournoi</span>
            <h1>{tournament?.tournament_name ?? 'Tournoi'}</h1>
          </div>
          <div className={styles.status}>{statusLabel(tournament)}</div>
        </section>

        <section className={styles.infoGrid}>
          <div className={styles.infoItem}>
            <span>Début</span>
            <strong>{tournament ? formatDate(tournament.start_date) : '-'}</strong>
          </div>
          <div className={styles.infoItem}>
            <span>Joueurs</span>
            <strong>{tournament ? `${tournament.players.length}/${tournament.max_players}` : '-'}</strong>
          </div>
          <div className={styles.infoItem}>
            <span>Minimum</span>
            <strong>{tournament?.min_players ?? '-'}</strong>
          </div>
          <div className={styles.infoItem}>
            <span>Niveaux</span>
            <strong>{tournament ? `${tournament.time_per_level} min` : '-'}</strong>
          </div>
        </section>

        <section className={styles.content}>
          <div className={styles.playersPanel}>
            <div className={styles.panelTitle}>
              <span>Participants</span>
              <strong>{profiles.length}</strong>
            </div>
            <div className={styles.seats}>
              {seats.map((playerId, index) => {
                const profile = profiles.find(item => item.user_id === playerId);
                return (
                  <div key={`${playerId ?? 'empty'}-${index}`} className={`${styles.seat} ${playerId ? styles.seatFilled : ''}`}>
                    <span>{String(index + 1).padStart(2, '0')}</span>
                    <strong>{profile?.username ?? (playerId ? 'Joueur' : 'Libre')}</strong>
                    <em>{profile ? `${profile.elo} elo` : ''}</em>
                  </div>
                );
              })}
            </div>
          </div>

          <aside className={styles.tablePanel}>
            <div className={styles.tableBadge}>
              <span>A</span>
              <span>K</span>
            </div>
            <h2>Ta table</h2>
            <p>{joined ? (tableId ? `Table #${tableId}` : 'Préconnexion en cours') : 'Inscris-toi depuis la page tournoi.'}</p>
            <button className={styles.primaryButton} onClick={openTable} disabled={!joined}>
              Rejoindre la table
            </button>
          </aside>
        </section>

        {feedback && <p className={styles.feedback}>{feedback}</p>}
      </main>
    </div>
  );
}
